namespace sv_a0ab73cf005c465dabc92ad5c38223fd.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

namespace sv_a0ab73cf005c465dabc92ad5c38223fd.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 30),
            new(2, "Margherita Pizza", "Traditional Neapolitan pizza with tomato, mozzarella, and fresh basil.", 45),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Grilled chicken chunks in a creamy spiced tomato sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cubes and aromatic spices.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, onion, and cilantro.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, and jalapeño.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken, topped with tangy green salsa.", 45),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (RecipesByCuisine.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_a0ab73cf005c465dabc92ad5c38223fd.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block" role="status">Refreshing…</div>
    }

    <ul>
        @foreach (var recipe in DisplayedRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="text-muted">(@recipe.PrepTimeMinutes min)</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _errorMessage;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();
            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        await CancelPendingRequestAsync();

        _errorMessage = null;
        _isRefreshing = _recipes is not null;
        _cts = new CancellationTokenSource();
        var token = _cts.Token;
        var cuisineId = CuisineId;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(cuisineId, token);
            _recipes = result;
            _loadedCuisineId = cuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was intentionally cancelled — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

